message:
Running command: # GPIO is on APB0 (0x40000000-0x4000FFFF), SYSTICK is on APB1 (0x40010000-0x4001FFFF)
# Both connect through the AHB matrix → AHB-to-APB bridge
# The force uses m0_haddr_req which is the "request" signal through an arbiter
# Let me check if SYSTICK address (0x4001E000) reaches APB1 vs GPIO address (0x40000100) reaches APB0

# First - let's verify SYSTICK is accessible by checking its ID
cd /tmp
cat > test_systick_id.v << 'EOF'
// Quick test: just read SYSTICK and GPIO ID registers
EOF

# Actually let me do a direct iverilog test reading GPIO0 ID register
cd /workspace/nc-project-20260529-210526
cat > /tmp/test_gpio_id_seq.vh << 'EOF'
    $display("GPIO_ID_TEST: start");
    // Read GPIO0 ID register (0x40000FFC)
    smoke_read32(32'h40000FFC, rd_data);
    $display("GPIO0 ID = 0x%08x (exp 0x00100020)", rd_data);
    // Read SYSTICK ID at 0x4001EFFC  
    smoke_read32(32'h4001EFFC, rd_data);
    $display("SYSTICK ID = 0x%08x", rd_data);
    // Read UART0 ID (0x40003FFC)
    smoke_read32(32'h40003FFC, rd_data);
    $display("UART0 ID = 0x%08x", rd_data);
    // Try SRAM write/read (0x20000000)
    smoke_write32(32'h20000000, 32'hDEADBEEF);
    smoke_read32(32'h20000000, rd_data);
    $display("SRAM read = 0x%08x (exp 0xDEADBEEF)", rd_data);
    // Try GPIO0 MODER write/read
    smoke_write32(32'h40000100, 32'h55555555);
    smoke_read32(32'h40000100, rd_data);
    $display("GPIO0 MODER after write = 0x%08x (exp 0x55555555)", rd_data);
EOF

# Patch the smoke bfm to use our test seq
iverilog -g2005-sv \
  -I.mspm33c321a_derivative_mcu_socgen_tmp/tb \
  -DTEST_SEQ_GPIO \
  -I/tmp \
  -fmspm33c321a_derivative_mcu/filelists/mspm33c321a_derivative_compute_ss.f \
  -fmspm33c321a_derivative_mcu/tb/mspm33c321a_derivative_compute_ss.f \
  -o /tmp/test_gpio3.vvp 2>&1 | tail -3 &
wait
timeout 20 /tmp/test_gpio2.vvp 2>&1 | grep -E "GPIO0|SYSTICK|UART0|SRAM|MODER|FW_BOOT|ID ="

